"""Evaluation metrics for analyst outputs."""

from __future__ import annotations

import json
import re
from typing import Any

from utils.llm_client import LLMClient


def _joined_text(parsed_response: dict[str, Any]) -> str:
    parts = [parsed_response.get("summary", "")]
    for key in ["key_insights", "patterns", "recommendations"]:
        parts.extend(parsed_response.get(key, []))
    return " ".join(str(part) for part in parts).lower()


def _response_items(parsed_response: dict[str, Any]) -> list[str]:
    """Return the list-like business content generated by the analyst."""
    items: list[str] = []
    for key in ["key_insights", "patterns", "recommendations"]:
        value = parsed_response.get(key, [])
        if isinstance(value, list):
            items.extend(str(item).strip() for item in value if str(item).strip())
    return items


def keyword_score(parsed_response: dict[str, Any], expected_keywords: list[str]) -> float:
    if not expected_keywords:
        return 0.0
    text = _joined_text(parsed_response)
    hits = sum(1 for keyword in expected_keywords if keyword.lower() in text)
    return hits / len(expected_keywords)


def recommendation_score(parsed_response: dict[str, Any]) -> float:
    recommendations = parsed_response.get("recommendations", [])
    if not recommendations:
        return 0.0
    action_terms = {"improve", "prioritize", "reduce", "increase", "target", "optimize", "focus"}
    coverage = min(len(recommendations) / 3, 1.0)
    actionability = 1.0 if any(any(term in rec.lower() for term in action_terms) for rec in recommendations) else 0.5
    return round(coverage * actionability, 4)


def completeness_score(parsed_response: dict[str, Any]) -> float:
    fields = ["summary", "key_insights", "patterns", "recommendations", "confidence"]
    available = 0
    for field in fields:
        value = parsed_response.get(field)
        if isinstance(value, list) and value:
            available += 1
        elif isinstance(value, str) and value.strip():
            available += 1
    return available / len(fields)


def groundedness_score(parsed_response: dict[str, Any], context: str) -> float:
    if not context:
        return 0.0
    text = _joined_text(parsed_response)
    tokens = [token for token in re.findall(r"[a-zA-Z0-9_]+", text) if len(token) > 3]
    if not tokens:
        return 0.0
    context_text = context.lower()
    overlaps = sum(1 for token in tokens if token in context_text)
    return min(overlaps / len(tokens), 1.0)


def insight_count(parsed_response: dict[str, Any]) -> int:
    """Count generated insights, patterns, and recommendations."""
    return len(_response_items(parsed_response))


def unique_insight_ratio(parsed_response: dict[str, Any]) -> float:
    """Measure how much of the structured business content is non-repetitive."""
    items = _response_items(parsed_response)
    if not items:
        return 0.0
    normalized = {
        re.sub(r"\s+", " ", re.sub(r"[^a-z0-9 ]", "", item.lower())).strip()
        for item in items
    }
    normalized.discard("")
    return round(len(normalized) / len(items), 4)


def avg_response_length(parsed_response: dict[str, Any]) -> float:
    """Average word count across summary and structured list items."""
    parts = [str(parsed_response.get("summary", "")).strip(), *_response_items(parsed_response)]
    lengths = [len(re.findall(r"\b\w+\b", part)) for part in parts if part]
    if not lengths:
        return 0.0
    return round(sum(lengths) / len(lengths), 4)


def business_specificity_score(parsed_response: dict[str, Any]) -> float:
    """Reward concrete ecommerce/business terms over generic advice."""
    terms = {
        "customer", "segment", "visitor", "channel", "traffic", "source",
        "conversion", "purchase", "revenue", "product", "category", "brand",
        "cart", "session", "engagement", "bounce", "exit", "month", "time",
        "target", "retention", "campaign", "merchandising", "funnel",
    }
    text = _joined_text(parsed_response)
    hits = sum(1 for term in terms if term in text)
    return round(min(hits / 8, 1.0), 4)


def json_validity_score(raw_response: str, parsed_response: dict[str, Any]) -> float:
    """Score whether raw output is valid JSON and follows the expected schema."""
    required = {"summary", "key_insights", "patterns", "recommendations", "confidence"}
    try:
        parsed_raw = json.loads(raw_response)
        valid_json = 1.0 if isinstance(parsed_raw, dict) else 0.0
        schema_score = len(required.intersection(parsed_raw.keys())) / len(required) if isinstance(parsed_raw, dict) else 0.0
        return round((valid_json + schema_score) / 2, 4)
    except Exception:
        populated_schema = len([key for key in required if parsed_response.get(key)]) / len(required)
        return round(populated_schema * 0.5, 4)


def retrieval_usefulness_score(parsed_response: dict[str, Any], context: str) -> float:
    """Estimate whether retrieved evidence was meaningfully used in the answer."""
    if not context:
        return 0.0
    answer = _joined_text(parsed_response)
    context_tokens = {
        token
        for token in re.findall(r"[a-zA-Z0-9_]+", context.lower())
        if len(token) > 4 and not token.isdigit()
    }
    if not context_tokens:
        return 0.0
    evidence_hits = sum(1 for token in context_tokens if token in answer)
    evidence_score = min(evidence_hits / 12, 1.0)
    concrete_values = re.findall(r"\b(?:true|false|new_visitor|returning_visitor|[a-z]{3,9}|\d+(?:\.\d+)?)\b", context.lower())
    value_hits = sum(1 for value in set(concrete_values) if value in answer)
    value_score = min(value_hits / 5, 1.0)
    return round((evidence_score * 0.7) + (value_score * 0.3), 4)


def heuristic_judge_scores(parsed_response: dict[str, Any], context: str) -> dict[str, float]:
    """Rubric-based fallback used when a live LLM judge is unavailable."""
    completeness = completeness_score(parsed_response)
    specificity = business_specificity_score(parsed_response)
    recommendations = recommendation_score(parsed_response)
    groundedness = groundedness_score(parsed_response, context)
    retrieval = retrieval_usefulness_score(parsed_response, context)
    uniqueness = unique_insight_ratio(parsed_response)
    length = avg_response_length(parsed_response)
    length_score = min(length / 18, 1.0)

    usefulness = 1 + 4 * ((recommendations * 0.35) + (specificity * 0.3) + (completeness * 0.2) + (length_score * 0.15))
    clarity = 1 + 4 * ((completeness * 0.45) + (uniqueness * 0.3) + (min(length / 30, 1.0) * 0.25))
    correctness = 1 + 4 * ((groundedness * 0.45) + (retrieval * 0.35) + (specificity * 0.2))
    return {
        "judge_usefulness": round(min(usefulness, 5.0), 2),
        "judge_clarity": round(min(clarity, 5.0), 2),
        "judge_correctness": round(min(correctness, 5.0), 2),
    }


def llm_judge_scores(
    question: str,
    parsed_response: dict[str, Any],
    context: str,
    judge_model: str = "openai/gpt-4o-mini",
    client: LLMClient | None = None,
) -> dict[str, float]:
    """Ask a judge LLM to rate usefulness, clarity, and correctness on a 1-5 scale."""
    client = client or LLMClient()
    fallback = heuristic_judge_scores(parsed_response, context)
    prompt = f"""
You are an impartial evaluator for a business analytics RAG agent.
Rate the answer on a 1-5 scale using this rubric:
- usefulness: would this help a business analyst or stakeholder make a decision?
- clarity: is the response readable, structured, and easy to understand?
- correctness: is the response supported by the retrieved dataset context and not hallucinated?

Question:
{question}

Retrieved dataset context:
{context or "[No retrieved context]"}

Answer JSON:
{json.dumps(parsed_response, indent=2)}

Return only JSON:
{{"judge_usefulness": 1-5, "judge_clarity": 1-5, "judge_correctness": 1-5}}
"""
    try:
        response = client.generate(
            prompt,
            judge_model,
            response_format={"type": "json_object"},
        )
        data = json.loads(response.text)
        return {
            "judge_usefulness": round(float(data.get("judge_usefulness", fallback["judge_usefulness"])), 2),
            "judge_clarity": round(float(data.get("judge_clarity", fallback["judge_clarity"])), 2),
            "judge_correctness": round(float(data.get("judge_correctness", fallback["judge_correctness"])), 2),
        }
    except Exception:
        return fallback
